import{_ as l,p as i,q as e,a1 as o}from"./framework-822ca1a4.js";const t={},r=o('<h1 id="一般将来时态" tabindex="-1"><a class="header-anchor" href="#一般将来时态" aria-hidden="true">#</a> 一般将来时态</h1><p>英语用一般将来时态表示将来发生的动作或者状态，也可以认为它就是用来谈论将来计划的，因为动作和状态都还没发生，所以只是计划而已。</p><p>一般将来时态的构成方式很简单，都是“将来助动词 + 动词原型”，但是“将来助动词”有好多个，所以构成方式也有几种！</p><h2 id="主语-will-be-表语-将来时间状语" tabindex="-1"><a class="header-anchor" href="#主语-will-be-表语-将来时间状语" aria-hidden="true">#</a> 主语 + will + be + 表语 + 将来时间状语</h2><ol><li>人称代词主格 + will + be + 形容词 + 将来时间状语</li></ol><ul><li>I will be busy tomorrow.</li><li>You will be tried tonight.</li><li>She will be rich in the future.</li><li>He will be capable next year.</li><li>They will be famous in the future.</li><li>We will be successful in the future.</li><li>It will be cheap tomorrow.</li></ul><ol start="2"><li>名词 + will + be + 形容词 + 将来时间状语</li></ol><ul><li>My teacher will be busy tomorrow.</li><li>Her boyfriend will be tired tonight.</li><li>The house will be cheap next year.</li><li>There girls will be famous in the future.</li></ul><ol start="3"><li>人称代词主格 + will + be + 名词 + 将来时间状语</li></ol><ul><li>I will be a leader next year.</li><li>They will be drivers tomorrow.</li><li>She will be my fan in the future.</li><li>It will be a park in the future.</li></ul><ol start="4"><li>名词 + will + be + 名词 + 将来时间状语</li></ol><ul><li>My daughter will be a doctor in the future.</li><li>The doctor will be her husband next year.</li><li>My fans will be rich man in the future.</li><li>The house will be my office next year.</li></ul><p>变一般疑问句，直接把助动词 will 移到句首，句尾加问号即可。</p><ul><li>Will it be cheap tomorrow?</li><li>Will you be busy tomorrow?</li></ul><h2 id="主语-will-动词原型-宾语-将来时间状语" tabindex="-1"><a class="header-anchor" href="#主语-will-动词原型-宾语-将来时间状语" aria-hidden="true">#</a> 主语 + will + 动词原型 + 宾语 + 将来时间状语</h2><ol><li>人称代词主格 + will + 不及物动词原型 + 状语</li></ol><ul><li>I will work tomorrow.</li><li>She will cry tomorrow.</li><li>You will die in the future.</li><li>They will sing tonight.</li><li>We will dance tonight.</li><li>It will run soon.</li><li>He will rest tomorrow.</li></ul><ol start="2"><li>名词 + will + 不及物动词原型 + 状语</li></ol><ul><li>My secretary will work tomorrow.</li><li>His driver will come soon.</li><li>The successful ladies will bathe tonight.</li><li>The car will hit the tree next second.</li></ul><ol start="3"><li>人称代词主格 + will + 及物动词原型 + 宾语</li></ol><ul><li>I will clean my desk tomorrow.</li><li>She will help me tomorrow.</li><li>They will buy a house next year.</li></ul><ol start="4"><li>名词 + will + 及物动词原型 + 宾语 + 状语</li></ol><ul><li>My fans will help me next year.</li><li>The strong man will help the aunt tonight.</li><li>These students will clean the classroom after school.</li></ul><p>变否定句，在 will 后面加 not 就行了，一般缩写 won&#39;t。</p><ul><li>My fans will not help me tomorrow.</li><li>I won&#39;t clean my desk tomorrow.</li></ul><p>变一般疑问句，直接把助动词 will 移到句首，句尾加问好即可。</p><ul><li>Will they buy beef tomorrow?</li><li>Will you clean your desk tomorrow?</li></ul><h2 id="一般将来时态的时间状语" tabindex="-1"><a class="header-anchor" href="#一般将来时态的时间状语" aria-hidden="true">#</a> 一般将来时态的时间状语</h2><ol><li>表示将来时间概念的时间副词：tomorrow，tonight，soon 等</li><li>next + 表示时间名词的单数：next year，next month，next week 等</li><li>after + 具体的时间点：after 5:00，after school 等</li><li>in + 一段时间或将来的年份：in a week，in 2050, in 2098 等</li></ol><h2 id="be-going-to" tabindex="-1"><a class="header-anchor" href="#be-going-to" aria-hidden="true">#</a> be going to</h2><p>be going to 可以代替住助动词 will。它有三种格式，分别是 is going to / are going to / am going to, 用的时候需要按照主语的不同格式进行变化。</p><p>主语是单数概念的词语，都用“is going to”，主语是复数概念或者 you ， 都用 “are going to”， 主语是 I 才能用 “am going to”。</p><ol><li>主语 + is/are/am + going + to + be + 表语 + 状语</li></ol><ul><li><p>I am going to be busy tomorrow.</p></li><li><p>You are going to be tired tonight.</p></li><li><p>She is going to be famous next year.</p></li><li><p>He is going to be strong next year.</p></li><li><p>It is going to be cheap tomorrow.</p></li><li><p>We are going to be rich in the future.</p></li><li><p>The are going to be healthy in the future.</p></li><li><p>My leader is going to be busy tomorrow.</p></li><li><p>My fans are going to be rich in the future.</p></li><li><p>I am going to be a leader in the future.</p></li><li><p>She is going to be a singer in the future.</p></li><li><p>They are going to be drivers tomorrow.</p></li><li><p>My friend is going to be a leader in the future.</p></li><li><p>My fans are going to be leaders in the future.</p></li></ul><ol start="2"><li>主语 + is/are/am + going + to + 动词原型 + 宾语 + 状语</li></ol><ul><li><p>I am going to bathe tonight.</p></li><li><p>You are going to work tomorrow.</p></li><li><p>She is going to run tomorrow.</p></li><li><p>My leader is going to work tomorrow.</p></li><li><p>My fans are going to dance tonight.</p></li><li><p>I am going to help her tomorrow.</p></li><li><p>She is going to buy a book next week.</p></li><li><p>They are going to clean the classroom tomorrow.</p></li><li><p>My leader is going to help her tonight.</p></li><li><p>My fans are going to buy gifts next month.</p></li></ul><p>变否定句，把“is going to/are going to/am going to”变成“is not going to/are not going to/am not going to”就可以了。</p><ul><li>I am not going to be busy tomorrow.</li><li>She is not going to buy a house next year.</li></ul><p>变一般疑问句，把“is/are/am going to”的“is/are/am”移到句首，句尾加问号。</p><ul><li>Are you going to be busy tomorrow?</li><li>Is she going to buy a house next year?</li></ul>',40),n=[r];function a(h,u){return i(),e("div",null,n)}const s=l(t,[["render",a],["__file","future-tense.html.vue"]]);export{s as default};
